window.SAMPLE_QUESTIONS=window.SAMPLE_QUESTIONS||[];
window.PAST_QUESTIONS_READY=(async()=>{
  const base64='';
  const binary=Uint8Array.from(atob(base64),c=>c.charCodeAt(0));
  const stream=new Blob([binary]).stream().pipeThrough(new DecompressionStream('gzip'));
  const text=await new Response(stream).text();
  window.ACTUAL_PAST_QUESTIONS=JSON.parse(text);
  window.SAMPLE_QUESTIONS.push(...window.ACTUAL_PAST_QUESTIONS);
  window.ACTUAL_PAST_QUESTIONS_META={count:window.ACTUAL_PAST_QUESTIONS.length,range:'2014-2023',source:'uploaded PDFs'};
})();
